Consider the following ANSI C program.

#include <stdio.h>
int main() {
    int i, j, count;
    count = 0;
    i = 0;
    for (j = -3; j <= 3; j++) {
        if ((j >= 0) && (i++))
            count = count + j;
    }
    printf("%d", count);
    return 0;
}

Which one of the following options is correct?

A. The program will not compile successfully
B. The program will compile successfully and output 10 when executed
C. The program will compile successfully and output 8 when executed
D. The program will compile successfully and output 13 when executed

Consider the following function definition.

int f(int x, int y) {
    for (int i = 0; i < y; i++) {
        x = x + x + y;
    }
    return x;
}

Which of the following statements is/are TRUE about the above function?

A. If the inputs are x = 20, y = 20, then the return value is greater than 2^20
B. If the inputs are x = 20, y = 20, then the return value is greater than 2^21
C. If the inputs are x = 10, y = 20, then the return value is greater than 2^20
D. If the inputs are x = 10, y = 20, then the return value is greater than 2^21

What is the output of the following program?

#include <stdio.h>
int funcf(int x);
int funcg(int y);

main() {
    int x = 5, y = 10, count;
    for (count = 1; count <= 2; ++count) {
        y += funcf(x) + funcg(x);
        printf("%d ", y);
    }
}

int funcf(int x) {
    static int y = 2;
    return y -= x;
}

int funcg(int y) {
    static int x = 2;
    return x -= y;
}

A. 43 50    B. 42 74    C. 33 37    D. 32 32
